using Microsoft.Data.Sqlite; var c = new SqliteConnection("Data Source=" + args[0]); c.Open(); var cmd = c.CreateCommand(); cmd.CommandText = "SELECT name FROM sqlite_master WHERE type='table' ORDER BY name"; var r = cmd.ExecuteReader(); var t = new System.Collections.Generic.List<string>(); while(r.Read()) t.Add(r.GetString(0)); System.Console.WriteLine(string.Join(", ", t)); c.Close();